package com.facilcomanda.productservice.entity; import jakarta.persistence.*; import java.math.BigDecimal; import java.time.LocalDateTime; import java.util.*; @Entity @Table(name="products", indexes=@Index(name="idx_product_org", columnList="organization_id")) public class Product { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(name="organization_id") private Long organizationId; private String name; private String description; private Integer stock; private BigDecimal unitPrice; private BigDecimal discount; private LocalDateTime expirationDate; @Version private Long version=0L; @ElementCollection @CollectionTable(name="product_category", joinColumns=@JoinColumn(name="product_id")) @Column(name="category_id") private Set<Long> categoryIds=new HashSet<>(); public Long getId(){return id;} public void setId(Long id){this.id=id;} public Long getOrganizationId(){return organizationId;} public void setOrganizationId(Long organizationId){this.organizationId=organizationId;} public String getName(){return name;} public void setName(String name){this.name=name;} public String getDescription(){return description;} public void setDescription(String description){this.description=description;} public Integer getStock(){return stock;} public void setStock(Integer stock){this.stock=stock;} public BigDecimal getUnitPrice(){return unitPrice;} public void setUnitPrice(BigDecimal unitPrice){this.unitPrice=unitPrice;} public BigDecimal getDiscount(){return discount;} public void setDiscount(BigDecimal discount){this.discount=discount;} public LocalDateTime getExpirationDate(){return expirationDate;} public void setExpirationDate(LocalDateTime expirationDate){this.expirationDate=expirationDate;} public Set<Long> getCategoryIds(){return categoryIds;} public void setCategoryIds(Set<Long> categoryIds){this.categoryIds=categoryIds;} public Long getVersion(){return version;} public void setVersion(Long version){this.version=version;} }
